const fileName = $json.body.fileName;
// Example: Project Charter Comparometer_accepted

const projectName = fileName
  .replace(/Project Charter/i, "")
  .replace(/_accepted/i, "")
  .trim()
  .toLowerCase()
  .replace(/\b\w/g, char => char.toUpperCase());

return [{
  fileId: $json.body.fileId,
  fileName,
  projectName,
  projectFolderId: $json.body.projectFolderId
}];

const msg = $('Message a model').first().json;

// 1. Extract OpenAI response safely
let raw =
  msg.output?.content?.[0]?.text ||
  msg.output?.[0]?.content?.[0]?.text ||
  msg.content?.[0]?.text;

if (!raw) {
  throw new Error('OpenAI response text not found');
}

// 2. Remove markdown fences
raw = raw
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

// 3. Parse JSON
const data = JSON.parse(raw);

// 4. Build rows — ONE ROW = ONE SUBTASK (REPEAT STORY DATA)
const rows = [];

data.forEach(item => {
  const acceptanceCriteria = Array.isArray(item["Acceptance Criteria"])
    ? item["Acceptance Criteria"].map(ac => `• ${ac}`).join('\n')
    : "";

  const subtasks = Array.isArray(item["Sub-tasks"])
    ? item["Sub-tasks"]
    : [];

  // If no subtasks, still create ONE row
  if (subtasks.length === 0) {
    rows.push({
      "Module/Subject": item["Module/Subject"] || "",
      "Epic/Module": item["Epic/Module"] || "",
      "User Story/Task": item["User Story/Task"] || "",
      "Acceptance Criteria": acceptanceCriteria,
      "Sub-tasks": ""
    });
    return;
  }

  // One row PER subtask — REPEAT ALL PARENT FIELDS
  for (const subtask of subtasks) {
    rows.push({
      "Module/Subject": item["Module/Subject"] || "",
      "Epic/Module": item["Epic/Module"] || "",
      "User Story/Task": item["User Story/Task"] || "",
      "Acceptance Criteria": acceptanceCriteria,
      "Sub-tasks": subtask
    });
  }
});

return rows;

// Derive project name & key
const projectName = $node["Code in JavaScript"].json.projectName;  

// Generate Jira-safe project key (max 10 chars, uppercase)
const letters = projectName
  .replace(/[^A-Za-z ]/g, " ")   // keep letters & spaces
  .split(" ")                    // split into words
  .filter(Boolean)
  .map(word => word[0])          // first letter of each word
  .join("")
  .toUpperCase();

// Enforce Jira rules: min 2, max 10
let projectKey = letters.substring(0, 10);

if (projectKey.length < 2) {
  // fallback: take first 2 letters of cleaned name
  projectKey = projectName
    .replace(/[^A-Za-z]/g, "")
    .substring(0, 2)
    .toUpperCase();
}

return [{
  projectName,
  projectKey,
  leadAccountId: "63281be03ac41ebde7680374" // 👈 replace with your real accountId
}];

const rows = $input.all();
const stories = {};

for (const { json } of rows) {
  const story = json["User Story/Task"];
  if (!story) continue;

  if (!stories[story]) {
    stories[story] = {
      projectKey: json.projectKey,
      epicKey: json.epicKey,
      summary: story,
      description: json["Acceptance Criteria"] || "",
      subtasks: []
    };
  }

  if (json["Sub-tasks"]) {
    stories[story].subtasks.push(json["Sub-tasks"]);
  }
}

return Object.values(stories).map(s => ({ json: s }));

const output = [];

for (const item of $input.all()) {
  const parentKey = item.json.key;
  const subtasks = Array.isArray(item.json.subtasks)
    ? item.json.subtasks
    : [];

  for (const task of subtasks) {
    if (!task || !task.trim()) continue;

    const cleanTask = task.replace(/^\d+\.\s*/, '').trim();

    output.push({
      json: {
        fields: {
          project: { key: parentKey.split('-')[0] },
          parent: { key: parentKey },
          summary: cleanTask,
          issuetype: { name: "Sub-task" }
        }
      }
    });
  }
}

return output;

return {
  json: {
    fields: {
      project: { key: $json.projectKey },
      summary: $json.summary,
      description: {
        type: "doc",
        version: 1,
        content: [{
          type: "paragraph",
          content: [{ type: "text", text: $json.description }]
        }]
      },
      issuetype: { name: "Story" },
      parent: { key: $json.epicKey }  // Epic Link
    },
    subtasks: $json.subtasks || []
  }
};

const rows = $input.all();
const epics = {};

for (const { json } of rows) {
  const epicName = json["Epic/Module"];
  if (!epicName) continue;

  if (!epics[epicName]) {
    epics[epicName] = {
      epicName,
      projectKey:$('Prepare Jira Project Data').first().json.projectKey ,
      rows: []
    };
  }

  epics[epicName].rows.push(json);
}

return Object.values(epics).map(e => ({ json: e }));

const output = [];
const items = $input.all();

for (const item of items) {
  const { epicKey, projectKey, rows } = item.json;

  if (!Array.isArray(rows)) continue;

  for (const row of rows) {
    output.push({
      json: {
        ...row,
        epicKey,
        projectKey,
      }
    });
  }
}

return output;

return {
  json: {
    epicKey: $json.key,
    projectKey:$('Prepare Epic Payload').item.json.projectKey,
    rows: $('Prepare Epic Payload').item.json.rows
  }
};

